import os
import pickle
import time
import hashlib
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)

class DiskCache:
    def __init__(self, cache_dir='cache', default_ttl=3600):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        if not os.path.exists(cache_dir):
            os.makedirs(cache_dir)
    
    def _get_cache_key(self, key):
        key_hash = hashlib.md5(key.encode()).hexdigest()
        return os.path.join(self.cache_dir, f"{key_hash}.pkl")
    
    def get(self, key):
        cache_file = self._get_cache_key(key)
        
        if not os.path.exists(cache_file):
            return None
        
        try:
            with open(cache_file, 'rb') as f:
                cached_data = pickle.load(f)
            
            if time.time() > cached_data['expires_at']:
                os.remove(cache_file)
                return None
            
            return cached_data['data']
        except (IOError, pickle.PickleError, KeyError):
            return None
    
    def set(self, key, value, ttl=None):
        if ttl is None:
            ttl = self.default_ttl
        
        cache_file = self._get_cache_key(key)
        
        cached_data = {
            'data': value,
            'created_at': time.time(),
            'expires_at': time.time() + ttl
        }
        
        try:
            with open(cache_file, 'wb') as f:
                pickle.dump(cached_data, f, protocol=pickle.HIGHEST_PROTOCOL)
            return True
        except (IOError, pickle.PickleError):
            return False
    
    def delete(self, key):
        cache_file = self._get_cache_key(key)
        
        if os.path.exists(cache_file):
            try:
                os.remove(cache_file)
                return True
            except IOError:
                return False
        return False
    
    def clear(self):
        for filename in os.listdir(self.cache_dir):
            file_path = os.path.join(self.cache_dir, filename)
            try:
                if os.path.isfile(file_path):
                    os.remove(file_path)
            except IOError:
                pass
    
    def cleanup_expired(self):
        current_time = time.time()
        for filename in os.listdir(self.cache_dir):
            file_path = os.path.join(self.cache_dir, filename)
            try:
                if os.path.isfile(file_path):
                    with open(file_path, 'rb') as f:
                        cached_data = pickle.load(f)
                    
                    if current_time > cached_data['expires_at']:
                        os.remove(file_path)
            except (IOError, pickle.PickleError, KeyError):
                pass


cache = DiskCache(cache_dir='api_cache', default_ttl=3600)


def cached_response(ttl=None, key_func=None):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if key_func:
                cache_key = key_func(*args, **kwargs)
            else:
                cache_key = f"{f.__name__}:{request.url}:{request.method}"
            
            cached_value = cache.get(cache_key)
            
            if cached_value is not None:
                return jsonify(cached_value)
            
            response_data = f(*args, **kwargs)
            
            if isinstance(response_data, tuple):
                data, status_code = response_data
            else:
                data = response_data
                status_code = 200
            
            if status_code == 200:
                cache.set(cache_key, data, ttl=ttl)
            
            return jsonify(data), status_code
        
        return decorated_function
    return decorator


